DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'billing_po_wo_supplementary_request_status_check'
  ) THEN
    ALTER TABLE billing.po_wo
      ADD CONSTRAINT billing_po_wo_supplementary_request_status_check
