  ADD COLUMN IF NOT EXISTS renewed_start_date date,
  ADD COLUMN IF NOT EXISTS renewed_end_date date;

COMMENT ON COLUMN billing.po_wo.renewed_po_wo_number IS 'Second/renewed PO/WO number after contract renewal (entered in app).';
COMMENT ON COLUMN billing.po_wo.renewed_total_contract_value IS 'Second/renewed total contract value after renewal (entered in app).';
COMMENT ON COLUMN billing.po_wo.renewed_start_date IS 'Renewal period start date (for renewed PO/WO).';
COMMENT ON COLUMN billing.po_wo.renewed_end_date IS 'Renewal period end date (for renewed PO/WO).';

-- =============================================================================
-- BEGIN: 20260409140000_billing_po_renewal_cycles.sql
-- =============================================================================
ALTER TABLE billing.po_wo
  ADD COLUMN IF NOT EXISTS renewal_cycles jsonb DEFAULT '[]'::jsonb;

COMMENT ON COLUMN billing.po_wo.renewal_cycles IS 'Array of renewal cycles: [{po_wo_number,total_contract_value,start_date,end_date,approved_at}]';

-- =============================================================================
-- BEGIN: 20260410130000_po_billing_logic_line_penalty.sql
-- =============================================================================
ALTER TABLE billing.po_wo
  ADD COLUMN IF NOT EXISTS monthly_duty_qty_mode text,
  ADD COLUMN IF NOT EXISTS lump_sum_billing_mode text;

COMMENT ON COLUMN billing.po_wo.monthly_duty_qty_mode IS 'Monthly: po_geometry = (actual/auth)*PO qty; duty_ratio = actual/auth as qty.';
COMMENT ON COLUMN billing.po_wo.lump_sum_billing_mode IS 'Lump Sum: normal | penalty (line penalty column) | fire_tender (extra Fire Tender row).';

ALTER TABLE billing.invoice_line_item
  ADD COLUMN IF NOT EXISTS line_penalty numeric(18,2) DEFAULT 0;

-- =============================================================================
-- BEGIN: 20260410150000_invoice_post_contract_buffer.sql
