  tables text[] := ARRAY[
    'billing.invoice',
    'billing.invoice_line_item',
    'billing.invoice_attachment'
  ];
BEGIN
  FOREACH t IN ARRAY tables
  LOOP
    IF to_regclass(t) IS NOT NULL THEN
