-- =============================================================================
-- BEGIN: 20260609180000_profiles_rls_definitive_fix.sql
-- =============================================================================
-- Definitive fix: profiles RLS "stack depth limit exceeded"
--
-- Root cause: policies on public.profiles that read public.profiles again
-- (inline EXISTS subquery or is_current_user_admin() without row_security off)
-- re-enter RLS → infinite recursion.
--
-- This migration:
-- 1. Recreates helper functions with SET row_security = off
-- 2. Drops ALL profiles RLS policies and recreates a non-recursive set
-- 3. Recreates admin_save_profile / admin_upsert_profile / get_profile_role
-- 4. Hardens sync_app_users trigger (no profiles reads)

-- ── Helper: super admin check (must NOT evaluate RLS on profiles) ─────────────
CREATE OR REPLACE FUNCTION public.is_current_user_admin()
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.profiles
    WHERE id = auth.uid()
      AND role IN ('super_admin', 'super_admin_pro')
  );
$$;

CREATE OR REPLACE FUNCTION public.get_profile_role(p_id uuid)
RETURNS text
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
  SELECT role FROM public.profiles WHERE id = p_id;
$$;

REVOKE ALL ON FUNCTION public.get_profile_role(uuid) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.get_profile_role(uuid) TO service_role;
GRANT EXECUTE ON FUNCTION public.get_profile_role(uuid) TO authenticated;

-- ── Service-role saves (User Management / edge functions) ─────────────────────
CREATE OR REPLACE FUNCTION public.admin_save_profile(
  p_id uuid,
  p_team text,
  p_role text,
  p_allowed_modules jsonb,
  p_employee_code text DEFAULT NULL,
  p_set_employee_code boolean DEFAULT false
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
DECLARE
  r public.profiles%ROWTYPE;
  code text;
  taken_email text;
BEGIN
  IF p_set_employee_code THEN
    code := NULLIF(btrim(p_employee_code), '');
    IF code IS NOT NULL THEN
      SELECT email INTO taken_email
      FROM public.profiles
      WHERE lower(btrim(employee_code)) = lower(code)
        AND id <> p_id
      LIMIT 1;

      IF FOUND THEN
        RAISE EXCEPTION 'Employee code "%" is already assigned to %.', code, COALESCE(taken_email, p_id::text)
          USING ERRCODE = '23505';
      END IF;
    END IF;
  END IF;

  UPDATE public.profiles
  SET
    team = p_team,
    role = p_role,
    allowed_modules = p_allowed_modules,
    employee_code = CASE WHEN p_set_employee_code THEN code ELSE employee_code END,
    updated_at = now()
  WHERE id = p_id
  RETURNING * INTO r;

  IF NOT FOUND THEN
    RETURN NULL;
  END IF;

  RETURN to_jsonb(r);
END;
$$;

REVOKE ALL ON FUNCTION public.admin_save_profile(uuid, text, text, jsonb, text, boolean) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.admin_save_profile(uuid, text, text, jsonb, text, boolean) TO service_role;

CREATE OR REPLACE FUNCTION public.admin_upsert_profile(
  p_id uuid,
  p_email text,
  p_username text,
  p_team text,
  p_role text,
  p_allowed_modules jsonb,
  p_employee_code text DEFAULT NULL,
  p_set_employee_code boolean DEFAULT false
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
DECLARE
  r public.profiles%ROWTYPE;
  code text;
BEGIN
  IF p_set_employee_code THEN
    code := NULLIF(btrim(p_employee_code), '');
  END IF;

  INSERT INTO public.profiles (id, email, username, team, role, allowed_modules, employee_code)
  VALUES (
    p_id,
    p_email,
    p_username,
    p_team,
    p_role,
    p_allowed_modules,
    CASE WHEN p_set_employee_code THEN code ELSE NULL END
  )
  ON CONFLICT (id) DO UPDATE
  SET
    email = EXCLUDED.email,
    username = EXCLUDED.username,
    team = EXCLUDED.team,
    role = EXCLUDED.role,
    allowed_modules = EXCLUDED.allowed_modules,
    employee_code = CASE WHEN p_set_employee_code THEN EXCLUDED.employee_code ELSE public.profiles.employee_code END,
    updated_at = now()
  RETURNING * INTO r;

  RETURN to_jsonb(r);
END;
$$;

REVOKE ALL ON FUNCTION public.admin_upsert_profile(uuid, text, text, text, text, jsonb, text, boolean) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.admin_upsert_profile(uuid, text, text, text, text, jsonb, text, boolean) TO service_role;

-- ── Drop every profiles policy (removes legacy inline-recursive policies) ─────
DO $$
DECLARE
  pol record;
BEGIN
  FOR pol IN
    SELECT policyname
    FROM pg_policies
    WHERE schemaname = 'public' AND tablename = 'profiles'
  LOOP
    EXECUTE format('DROP POLICY IF EXISTS %I ON public.profiles', pol.policyname);
  END LOOP;
END;
$$;

CREATE POLICY "Users can read own profile"
  ON public.profiles FOR SELECT
  USING (id = auth.uid());

CREATE POLICY "Admins can read all profiles"
  ON public.profiles FOR SELECT
  USING (public.is_current_user_admin());

CREATE POLICY "Users can insert own profile"
  ON public.profiles FOR INSERT
  WITH CHECK (id = auth.uid());

CREATE POLICY "Users can update own profile"
  ON public.profiles FOR UPDATE
  USING (id = auth.uid())
  WITH CHECK (id = auth.uid());

CREATE POLICY "Admins can update any profile"
  ON public.profiles FOR UPDATE
  USING (public.is_current_user_admin())
  WITH CHECK (public.is_current_user_admin());

-- ── app_users sync trigger: never read profiles (writes app_users only) ───────
CREATE OR REPLACE FUNCTION public.trg_sync_app_users_from_profiles()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
BEGIN
  IF to_regclass('public.app_users') IS NULL THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.app_users (id, email, full_name)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.username, split_part(COALESCE(NEW.email, 'user@local'), '@', 1))
  )
  ON CONFLICT (id) DO UPDATE
  SET
    email = EXCLUDED.email,
    full_name = EXCLUDED.full_name;

  RETURN NEW;
EXCEPTION
  WHEN undefined_column THEN
    RETURN NEW;
  WHEN OTHERS THEN
    RETURN NEW;
END;
$$;

ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS employee_code text;

NOTIFY pgrst, 'reload schema';

-- =============================================================================
-- BEGIN: 20260609190000_fix_auth_user_created_trigger.sql
-- =============================================================================
-- Fix "Database error creating new user" when auth.users has a trigger that inserts into public.profiles.
-- Triggers on auth.users run as supabase_auth_admin; the handler must be SECURITY DEFINER and must not
-- abort the auth transaction if the profile insert fails (admin-create-user upserts the profile afterward).

CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
BEGIN
  INSERT INTO public.profiles (id, email, username, team, role, allowed_modules, employee_code)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(
      NULLIF(btrim(NEW.raw_user_meta_data->>'username'), ''),
      NULLIF(btrim(NEW.raw_user_meta_data->>'full_name'), ''),
      split_part(COALESCE(NEW.email, 'user@local'), '@', 1)
    ),
    NULLIF(btrim(NEW.raw_user_meta_data->>'team'), ''),
    COALESCE(NULLIF(btrim(NEW.raw_user_meta_data->>'role'), ''), 'executive'),
    COALESCE(NEW.raw_user_meta_data->'allowed_modules', '[]'::jsonb),
    NULLIF(btrim(NEW.raw_user_meta_data->>'employee_code'), '')
  )
  ON CONFLICT (id) DO NOTHING;

  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    RAISE WARNING 'handle_new_user skipped profile insert for %: %', NEW.id, SQLERRM;
    RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW
  EXECUTE FUNCTION public.handle_new_user();

-- =============================================================================
-- BEGIN: 20260609200000_fix_profiles_employee_code_sync.sql
-- =============================================================================
-- Fix stack depth when assigning profiles.employee_code linked to employee master.
-- See supabase/scripts/fix_profiles_employee_code_sync.sql (same content).

CREATE OR REPLACE FUNCTION public.current_user_has_admin_module_access()
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
  SELECT
    NOT EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = auth.uid())
    OR EXISTS (
      SELECT 1
      FROM public.profiles p
      WHERE p.id = auth.uid()
        AND (
          p.role IN ('admin', 'super_admin', 'super_admin_pro')
          OR p.team = 'admin'
          OR COALESCE(p.allowed_modules, '[]'::jsonb) ? 'admin'
        )
    );
$$;

CREATE OR REPLACE FUNCTION public.current_user_can_access_module(module_key text)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
  WITH requested AS (
    SELECT lower(trim(coalesce(module_key, ''))) AS key
  )
  SELECT EXISTS (
    SELECT 1
    FROM public.profiles p
    CROSS JOIN requested r
    WHERE p.id = auth.uid()
      AND r.key <> ''
      AND (
        p.role IN ('super_admin', 'super_admin_pro')
        OR (
          p.role = 'admin'
          AND r.key NOT IN ('usermanagement', 'softwaresubscriptions')
        )
        OR lower(coalesce(p.team, '')) = r.key
        OR EXISTS (
          SELECT 1
          FROM jsonb_array_elements_text(coalesce(p.allowed_modules, '[]'::jsonb)) AS m(value)
          WHERE lower(m.value) = r.key
        )
      )
  );
$$;

CREATE OR REPLACE FUNCTION public.sync_auth_user_employee_code()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, auth
SET row_security = off
AS $$
BEGIN
  UPDATE auth.users
  SET raw_user_meta_data = coalesce(raw_user_meta_data, '{}'::jsonb)
    || CASE
      WHEN NEW.employee_code IS NULL OR btrim(NEW.employee_code) = '' THEN
        coalesce(raw_user_meta_data, '{}'::jsonb) - 'employee_code'
      ELSE
        jsonb_build_object('employee_code', btrim(NEW.employee_code))
    END
  WHERE id = NEW.id;
  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    RAISE WARNING 'sync_auth_user_employee_code failed for %: %', NEW.id, SQLERRM;
    RETURN NEW;
END;
$$;

CREATE OR REPLACE FUNCTION public.sync_employee_master_from_profile_employee_code()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
BEGIN
  IF NEW.employee_code IS NULL OR btrim(NEW.employee_code) = '' THEN
    RETURN NEW;
  END IF;

  UPDATE public.admin_ifsp_employee_master m
  SET user_id = NEW.id
  WHERE coalesce(m.status, 'Active') ILIKE 'Active'
    AND (
      public.norm_emp_code(m.employee_code) = public.norm_emp_code(NEW.employee_code)
      OR public.norm_emp_code(m.employee_id::text) = public.norm_emp_code(NEW.employee_code)
    )
    AND (m.user_id IS NULL OR m.user_id = NEW.id);

  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    RAISE WARNING 'sync_employee_master_from_profile_employee_code failed for %: %', NEW.id, SQLERRM;
    RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_sync_employee_master_from_profile_code ON public.profiles;
DROP FUNCTION IF EXISTS public.sync_employee_master_from_profile_code();

DROP TRIGGER IF EXISTS trg_sync_auth_user_employee_code ON public.profiles;
CREATE TRIGGER trg_sync_auth_user_employee_code
  AFTER INSERT OR UPDATE OF employee_code ON public.profiles
  FOR EACH ROW
  EXECUTE FUNCTION public.sync_auth_user_employee_code();

DROP TRIGGER IF EXISTS trg_sync_employee_master_from_profile_employee_code ON public.profiles;
CREATE TRIGGER trg_sync_employee_master_from_profile_employee_code
  AFTER INSERT OR UPDATE OF employee_code ON public.profiles
  FOR EACH ROW
  EXECUTE FUNCTION public.sync_employee_master_from_profile_employee_code();

NOTIFY pgrst, 'reload schema';

-- =============================================================================
-- BEGIN: 20260610120000_fire_tender_costing_templates.sql
-- =============================================================================
-- Template-wise (vehicle category) costing sheets for the Fire Tender module.
--
-- Templates: 'Fire Tender' (existing), 'Rescue vehicle', 'Rhino/QRV/ERV', 'Ambulance'.
-- The MAIN costing sheet (main_components / price_master) is scoped per template.
-- Accessories and MOC remain global (shared across templates).
--
-- Idempotent: safe to run more than once.

-- 1) New columns -------------------------------------------------------------
ALTER TABLE public.tenders
  ADD COLUMN IF NOT EXISTS costing_template text DEFAULT 'Fire Tender';

ALTER TABLE public.main_components
  ADD COLUMN IF NOT EXISTS template text DEFAULT 'Fire Tender';

ALTER TABLE public.price_master
  ADD COLUMN IF NOT EXISTS template text DEFAULT 'Fire Tender';

-- 2) Backfill existing rows to the default template --------------------------
UPDATE public.tenders        SET costing_template = 'Fire Tender' WHERE costing_template IS NULL;
UPDATE public.main_components SET template        = 'Fire Tender' WHERE template IS NULL;
UPDATE public.price_master   SET template        = 'Fire Tender' WHERE template IS NULL;

-- 3) Seed the new templates by cloning the Fire Tender catalog ---------------
--    (only when the target template has no rows yet, so re-runs are safe)
DO $$
DECLARE
  tmpl text;
BEGIN
  FOREACH tmpl IN ARRAY ARRAY['Rescue vehicle', 'Rhino/QRV/ERV', 'Ambulance'] LOOP
    IF NOT EXISTS (SELECT 1 FROM public.main_components WHERE template = tmpl) THEN
      INSERT INTO public.main_components
        (main_component, sub_category1, sub_category2, sub_category3, sub_category4, sub_category5, user_id, template)
      SELECT main_component, sub_category1, sub_category2, sub_category3, sub_category4, sub_category5, user_id, tmpl
      FROM public.main_components
      WHERE template = 'Fire Tender';
    END IF;

    IF NOT EXISTS (SELECT 1 FROM public.price_master WHERE template = tmpl) THEN
      INSERT INTO public.price_master
        (main_component, sub_category1, sub_category2, sub_category3, sub_category4, sub_category5,
         manual_sub_category, weight, unit_cost, is_new, user_id, template)
      SELECT main_component, sub_category1, sub_category2, sub_category3, sub_category4, sub_category5,
         manual_sub_category, weight, unit_cost, false, user_id, tmpl
      FROM public.price_master
      WHERE template = 'Fire Tender';
    END IF;
  END LOOP;
END $$;

COMMENT ON COLUMN public.tenders.costing_template IS
  'Fire Tender costing template / vehicle category that selects which main_components drive this tender''s costing sheet.';
COMMENT ON COLUMN public.main_components.template IS
  'Costing template this main component belongs to (Fire Tender, Rescue vehicle, Rhino/QRV/ERV, Ambulance).';
COMMENT ON COLUMN public.price_master.template IS
  'Costing template this price-master row belongs to.';

-- =============================================================================
-- BEGIN: 20260610140000_fire_tender_audit_logs_price_master_versions_rls.sql
-- =============================================================================
-- Fire Tender audit trail: audit_logs + price_master_versions
-- Append-only history for unit_cost / price master changes.
-- Reuses current_user_has_fire_tender_shared_catalog_access() from
-- 20260515143000_fire_tender_shared_catalog_rls.sql

-- ---------------------------------------------------------------------------
-- audit_logs
-- ---------------------------------------------------------------------------
DO $$
BEGIN
  IF to_regclass('public.audit_logs') IS NULL THEN
    RAISE NOTICE 'public.audit_logs does not exist — skipping RLS setup';
    RETURN;
  END IF;

  EXECUTE 'ALTER TABLE public.audit_logs ENABLE ROW LEVEL SECURITY';

  EXECUTE 'DROP POLICY IF EXISTS "Users can insert their own data" ON public.audit_logs';
  EXECUTE 'DROP POLICY IF EXISTS "Users can view their own data" ON public.audit_logs';
  EXECUTE 'DROP POLICY IF EXISTS "Users can update their own data" ON public.audit_logs';
  EXECUTE 'DROP POLICY IF EXISTS "Users can delete their own data" ON public.audit_logs';
  EXECUTE 'DROP POLICY IF EXISTS fire_tender_audit_logs_select ON public.audit_logs';
  EXECUTE 'DROP POLICY IF EXISTS fire_tender_audit_logs_insert ON public.audit_logs';

  EXECUTE $p$
    CREATE POLICY fire_tender_audit_logs_select
      ON public.audit_logs FOR SELECT
      TO authenticated
      USING (public.current_user_has_fire_tender_shared_catalog_access())
  $p$;

  EXECUTE $p$
    CREATE POLICY fire_tender_audit_logs_insert
      ON public.audit_logs FOR INSERT
      TO authenticated
      WITH CHECK (
        public.current_user_has_fire_tender_shared_catalog_access()
        AND (user_id IS NULL OR user_id = auth.uid())
      )
  $p$;

  -- Immutable audit trail: no UPDATE/DELETE policies for authenticated users.
  REVOKE ALL ON public.audit_logs FROM anon;
  GRANT SELECT, INSERT ON public.audit_logs TO authenticated;
END $$;

COMMENT ON TABLE public.audit_logs IS
  'Fire Tender unit-cost audit trail. Append-only; RLS scoped to Fire Tender team / module users and super admins.';

-- ---------------------------------------------------------------------------
-- price_master_versions (app table name; also covers legacy price_master_version)
-- ---------------------------------------------------------------------------
DO $$
DECLARE
  tbl text;
BEGIN
  IF to_regclass('public.price_master_versions') IS NOT NULL THEN
    tbl := 'price_master_versions';
  ELSIF to_regclass('public.price_master_version') IS NOT NULL THEN
    tbl := 'price_master_version';
  ELSE
    RAISE NOTICE 'public.price_master_versions / price_master_version does not exist — skipping RLS setup';
    RETURN;
  END IF;

  EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', tbl);

  EXECUTE format('DROP POLICY IF EXISTS "Users can insert their own data" ON public.%I', tbl);
  EXECUTE format('DROP POLICY IF EXISTS "Users can view their own data" ON public.%I', tbl);
  EXECUTE format('DROP POLICY IF EXISTS "Users can update their own data" ON public.%I', tbl);
  EXECUTE format('DROP POLICY IF EXISTS "Users can delete their own data" ON public.%I', tbl);
  EXECUTE format('DROP POLICY IF EXISTS fire_tender_price_master_versions_select ON public.%I', tbl);
  EXECUTE format('DROP POLICY IF EXISTS fire_tender_price_master_versions_insert ON public.%I', tbl);

  EXECUTE format($p$
    CREATE POLICY fire_tender_price_master_versions_select
      ON public.%I FOR SELECT
      TO authenticated
      USING (public.current_user_has_fire_tender_shared_catalog_access())
  $p$, tbl);

  EXECUTE format($p$
    CREATE POLICY fire_tender_price_master_versions_insert
      ON public.%I FOR INSERT
      TO authenticated
      WITH CHECK (
        public.current_user_has_fire_tender_shared_catalog_access()
        AND user_id IS NOT NULL
        AND user_id = auth.uid()
      )
  $p$, tbl);

  -- Immutable version history: no UPDATE/DELETE policies for authenticated users.
  EXECUTE format('REVOKE ALL ON public.%I FROM anon', tbl);
  EXECUTE format('GRANT SELECT, INSERT ON public.%I TO authenticated', tbl);
END $$;

-- =============================================================================
-- BEGIN: 20260610160000_employee_code_public_billing.sql
-- =============================================================================
-- Denormalize employee_code across public + billing (NOT indus_one).
-- Canonical person key: admin_ifsp_employee_master.employee_code (= profiles.employee_code).
-- UUID columns (user_id, created_by, …) remain for auth/RLS; joins/reporting use employee_code.

-- ---------------------------------------------------------------------------
-- Helpers
-- ---------------------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.employee_code_for_user(p_user_id uuid)
RETURNS text
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
  SELECT NULLIF(
    btrim(
      COALESCE(
        (SELECT p.employee_code FROM public.profiles p WHERE p.id = p_user_id),
        (SELECT m.employee_code FROM public.admin_ifsp_employee_master m WHERE m.user_id = p_user_id)
      )
    ),
    ''
  );
$$;

COMMENT ON FUNCTION public.employee_code_for_user(uuid) IS
  'Resolve ERP employee_code from auth user id (profiles first, then employee master).';

CREATE OR REPLACE FUNCTION public.employee_code_for_master(p_master_id bigint)
RETURNS text
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
SET row_security = off
AS $$
  SELECT NULLIF(btrim(employee_code), '')
  FROM public.admin_ifsp_employee_master
  WHERE id = p_master_id;
$$;

COMMENT ON FUNCTION public.employee_code_for_master(bigint) IS
  'Resolve employee_code from admin_ifsp_employee_master.id.';

CREATE OR REPLACE FUNCTION public._table_has_column(
  p_schema text, p_table text, p_column text
)
RETURNS boolean
LANGUAGE sql
STABLE
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM information_schema.columns
    WHERE table_schema = p_schema
      AND table_name = p_table
      AND column_name = p_column
  );
$$;

CREATE OR REPLACE FUNCTION public._backfill_employee_code_from_user(
  p_schema text,
  p_table text,
  p_user_col text,
  p_code_col text
)
RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
  IF NOT public._table_has_column(p_schema, p_table, p_user_col)
     OR NOT public._table_has_column(p_schema, p_table, p_code_col) THEN
    RETURN;
  END IF;
  EXECUTE format(
    $q$
    UPDATE %I.%I t
    SET %I = public.employee_code_for_user(t.%I)
    WHERE t.%I IS NOT NULL
      AND (t.%I IS NULL OR btrim(t.%I) = '')
    $q$,
    p_schema, p_table, p_code_col, p_user_col, p_user_col, p_code_col, p_code_col
  );
END;
$$;

CREATE OR REPLACE FUNCTION public._backfill_employee_code_from_master(
  p_schema text,
  p_table text,
  p_master_col text,
  p_code_col text DEFAULT 'employee_code'
)
RETURNS void
LANGUAGE plpgsql
AS $$
BEGIN
  IF NOT public._table_has_column(p_schema, p_table, p_master_col)
     OR NOT public._table_has_column(p_schema, p_table, p_code_col) THEN
    RETURN;
  END IF;
  EXECUTE format(
    $q$
    UPDATE %I.%I t
    SET %I = public.employee_code_for_master(t.%I)
    WHERE t.%I IS NOT NULL
      AND (t.%I IS NULL OR btrim(t.%I) = '')
    $q$,
    p_schema, p_table, p_code_col, p_master_col, p_master_col, p_code_col, p_code_col
  );
END;
$$;

-- ---------------------------------------------------------------------------
-- billing schema
-- ---------------------------------------------------------------------------
DO $billing$
BEGIN
  IF EXISTS (
    SELECT 1 FROM information_schema.tables
    WHERE table_schema = 'billing' AND table_name = 'invoice'
  ) THEN
    ALTER TABLE billing.invoice
      ADD COLUMN IF NOT EXISTS created_by_employee_code text;
    CREATE INDEX IF NOT EXISTS idx_billing_invoice_created_by_employee_code
      ON billing.invoice (lower(btrim(created_by_employee_code)))
      WHERE created_by_employee_code IS NOT NULL AND btrim(created_by_employee_code) <> '';
    PERFORM public._backfill_employee_code_from_user('billing', 'invoice', 'created_by', 'created_by_employee_code');
    COMMENT ON COLUMN billing.invoice.created_by_employee_code IS
      'Denormalized actor code; use for joins/reporting instead of created_by uuid.';
  END IF;
END $billing$;

-- ---------------------------------------------------------------------------
-- public — HR payroll (subject employee)
-- ---------------------------------------------------------------------------
DO $hr$
DECLARE
  t text;
  master_tables text[] := ARRAY[
    'hr_employee_payroll_profile',
    'hr_payroll_employee_monthly_summary',
    'hr_payroll_employee_component_values',
    'hr_payroll_manual_inputs',
    'hr_payroll_pf_details',
    'hr_payroll_esic_details',
    'hr_payroll_pt_details',
    'hr_payroll_tds_details',
    'hr_payroll_loans',
    'hr_payroll_payslips'
  ];
BEGIN
  FOREACH t IN ARRAY master_tables LOOP
    IF EXISTS (
      SELECT 1 FROM information_schema.tables
      WHERE table_schema = 'public' AND table_name = t
    ) THEN
      EXECUTE format('ALTER TABLE public.%I ADD COLUMN IF NOT EXISTS employee_code text', t);
      PERFORM public._backfill_employee_code_from_master('public', t, 'employee_master_id', 'employee_code');
      EXECUTE format(
        'CREATE INDEX IF NOT EXISTS %I ON public.%I (lower(btrim(employee_code))) WHERE employee_code IS NOT NULL AND btrim(employee_code) <> %L',
        'idx_' || t || '_employee_code', t, ''
      );
    END IF;
  END LOOP;

  -- payroll audit actors
  IF public._table_has_column('public', 'hr_site_payroll_formula_sets', 'created_by') THEN
    ALTER TABLE public.hr_site_payroll_formula_sets ADD COLUMN IF NOT EXISTS created_by_employee_code text;
    PERFORM public._backfill_employee_code_from_user('public', 'hr_site_payroll_formula_sets', 'created_by', 'created_by_employee_code');
  END IF;

  IF public._table_has_column('public', 'hr_payroll_runs', 'created_by') THEN
    ALTER TABLE public.hr_payroll_runs ADD COLUMN IF NOT EXISTS created_by_employee_code text;
    PERFORM public._backfill_employee_code_from_user('public', 'hr_payroll_runs', 'created_by', 'created_by_employee_code');
  END IF;
  IF public._table_has_column('public', 'hr_payroll_runs', 'finalized_by') THEN
    ALTER TABLE public.hr_payroll_runs ADD COLUMN IF NOT EXISTS finalized_by_employee_code text;
    PERFORM public._backfill_employee_code_from_user('public', 'hr_payroll_runs', 'finalized_by', 'finalized_by_employee_code');
  END IF;

  IF public._table_has_column('public', 'hr_payroll_manual_inputs', 'created_by') THEN
    ALTER TABLE public.hr_payroll_manual_inputs ADD COLUMN IF NOT EXISTS created_by_employee_code text;
    PERFORM public._backfill_employee_code_from_user('public', 'hr_payroll_manual_inputs', 'created_by', 'created_by_employee_code');
  END IF;
  IF public._table_has_column('public', 'hr_payroll_manual_inputs', 'approved_by') THEN
    ALTER TABLE public.hr_payroll_manual_inputs ADD COLUMN IF NOT EXISTS approved_by_employee_code text;
    PERFORM public._backfill_employee_code_from_user('public', 'hr_payroll_manual_inputs', 'approved_by', 'approved_by_employee_code');
  END IF;

  IF public._table_has_column('public', 'hr_payroll_audit_logs', 'actor_id') THEN
    ALTER TABLE public.hr_payroll_audit_logs ADD COLUMN IF NOT EXISTS actor_employee_code text;
    PERFORM public._backfill_employee_code_from_user('public', 'hr_payroll_audit_logs', 'actor_id', 'actor_employee_code');
  END IF;
END $hr$;

-- ---------------------------------------------------------------------------
-- public — AMC
-- ---------------------------------------------------------------------------
DO $amc$
BEGIN
  IF public._table_has_column('public', 'amc_customers', 'created_by') THEN
    ALTER TABLE public.amc_customers ADD COLUMN IF NOT EXISTS created_by_employee_code text;
    ALTER TABLE public.amc_customers ADD COLUMN IF NOT EXISTS updated_by_employee_code text;
    PERFORM public._backfill_employee_code_from_user('public', 'amc_customers', 'created_by', 'created_by_employee_code');
